import{_ as a,o as t,c as d,ac as o}from"./chunks/framework.DnBnwVZk.js";const u=JSON.parse('{"title":"AndroidTV安装CA证书","description":"","frontmatter":{"date":"2024-10-01T22:35:54.000Z","categories":["Linux"],"tags":["Linux","AndroidTV","Self Host"],"publish":true},"headers":[],"relativePath":"views/linux/nas/AndroidTVCA.md","filePath":"views/linux/nas/AndroidTVCA.md","lastUpdated":1775714960000}'),i={name:"views/linux/nas/AndroidTVCA.md"};function r(s,e,c,n,l,h){return t(),d("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1727822154000"},[...e[0]||(e[0]=[o('<h1 id="androidtv安装ca证书" tabindex="-1">AndroidTV安装CA证书 <a class="header-anchor" href="#androidtv安装ca证书" aria-label="Permalink to &quot;AndroidTV安装CA证书&quot;">​</a></h1><ol><li>openssl x509 -inform PEM -subject_hash_old -in your-certificate.pem | head -n 1 将 your-certificate.pem 替换成你的证书全路径，执行之后会得到一个 hash 值，如：711d79cc</li><li>将你本地的 xxx.pem 证书 重命名为 上一步得到的 hash.0，如：711d79cc.0</li><li>通过 adb 链接设备:<code>sudo adb connect 192.168.1.xxx</code></li><li>切换为root:<code>adb root</code></li><li>重新mount分区:<code>adb remount</code></li><li>文件传送：<code>adb push hash.0 /system/etc/security/cacerts/hash.0</code></li><li>更改权限:<code>adb shell chmod 644 /system/etc/security/cacerts/hash.0</code></li></ol><p>ps : /system/etc/security/cacerts TV 设备的证书存储在此目录下，最终目的就是将需要安装的证书，push 到这里即代表已安装。</p><p>参考：<a href="https://cmlgithub.github.io/2021/06/30/Android%20TV%20Phone%20%E5%AE%89%E8%A3%85%20CA%20%E8%AF%81%E4%B9%A6/" target="_blank" rel="noreferrer">Android TV、Phone 安装 CA 证书</a></p>',4)])])}const A=a(i,[["render",r]]);export{u as __pageData,A as default};
